import javax.jws.WebMethod;
import javax.jws.WebParam;
import javax.jws.WebService;
import org.w3c.dom.Document;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.StringReader;

@WebService
public class XMLProcessingService {

    @WebMethod(operationName = "processXML")
    public String processXML(@WebParam(name = "xmlData") String xmlData) {
        try {
            // Parse the incoming SOAP message using DocumentBuilder
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new StringReader(xmlData));

            // Process complex XML structures with nested entities
            // Example: Extract data from a specific element
            String data = document.getElementsByTagName("data").item(0).getTextContent();

            // Handle large XML payloads for data import
            // Example: Log the received data
            System.out.println("Received data: " + data);

            return "Data processed successfully";
        } catch (Exception e) {
            e.printStackTrace();
            return "Error processing data: " + e.getMessage();
        }
    }
}